import{_ as h,y as i,a,o as c,ag as g,D as u}from"./chunks/framework.RVu0gECZ.js";const v=JSON.parse('{"title":"Thương mại điện tử nhiều người thuê","description":"","frontmatter":{},"headers":[],"relativePath":"multi-tenant-ecommerce/introduction.md","filePath":"multi-tenant-ecommerce/introduction.md","lastUpdated":1775737044000}'),o={name:"multi-tenant-ecommerce/introduction.md"};function e(r,n,p,m,l,d){const t=i("ImagePopup");return c(),a("div",null,[n[0]||(n[0]=g('<h1 id="thuong-mai-đien-tu-nhieu-nguoi-thue" tabindex="-1">Thương mại điện tử nhiều người thuê <a class="header-anchor" href="#thuong-mai-đien-tu-nhieu-nguoi-thue" aria-label="Permalink to &quot;Thương mại điện tử nhiều người thuê&quot;">​</a></h1><p><a href="https://VNS.com/en/laravel-multi-tenant-saas/" target="_blank" rel="noreferrer">Thương mại điện tử nhiều người thuê</a> tại VNS cho phép doanh nghiệp xây dựng nền tảng SaaS, nơi nhiều nhà cung cấp hoặc người bán có thể tạo và quản lý cửa hàng riêng của họ trong cùng một hệ thống.</p><p>Mỗi người thuê (người bán) có một giao diện cửa hàng riêng với toàn quyền kiểm soát sản phẩm, danh mục, đơn hàng và khách hàng, trong khi chủ nền tảng quản lý toàn bộ hạ tầng, đăng ký và mô hình doanh thu. Cách làm này giúp giảm chi phí vận hành cho người bán vì họ không cần đầu tư vào một hệ thống thương mại điện tử riêng.</p><h3 id="quan-ly-quan-tri-vien-cap-cao" tabindex="-1">Quản lý quản trị viên cấp cao <a class="header-anchor" href="#quan-ly-quan-tri-vien-cap-cao" aria-label="Permalink to &quot;Quản lý quản trị viên cấp cao&quot;">​</a></h3><p>Quản trị viên cấp cao là người có quyền cao nhất trong hệ thống SaaS, chịu trách nhiệm giám sát người thuê, nhân viên và toàn bộ hoạt động của nền tảng.</p><p>Vai trò này bao gồm quản lý người bán (người thuê), phân quyền cho nhân viên (đại lý) và đảm bảo mọi thứ vận hành trơn tru trong hệ thống.</p><p>Quản trị viên cấp cao cũng thiết lập sản phẩm hiển thị, quản lý kênh và thiết kế giao diện để giữ trải nghiệm và thương hiệu nhất quán cho tất cả các cửa hàng thuê.</p><p>Họ cũng quản lý các trang CMS, email và cài đặt chung để đảm bảo giao tiếp rõ ràng và quản trị nền tảng tốt hơn.</p><h3 id="quan-ly-nguoi-thue" tabindex="-1">Quản lý người thuê <a class="header-anchor" href="#quan-ly-nguoi-thue" aria-label="Permalink to &quot;Quản lý người thuê&quot;">​</a></h3><p>Quản lý người thuê trong SaaS giúp người thuê đăng ký và tạo cửa hàng trực tuyến nhanh chóng bằng cách điền thông tin đăng nhập, cá nhân và tổ chức của họ.</p><p>Sau khi đăng ký, giao diện cửa hàng của người thuê sẽ tự động được thiết lập để họ có thể bắt đầu bán hàng ngay mà không gặp trở ngại kỹ thuật nào.</p><p>Sử dụng bảng quản trị của người thuê, người thuê có thể quản lý sản phẩm, danh mục, thuộc tính, khách hàng, v.v. qua giao diện thân thiện giống VNS.</p><p>Người thuê cũng có thể quản lý đơn hàng bằng cách lập hóa đơn, tạo lô hàng và dùng các tùy chọn menu khác để vận hành cửa hàng hiệu quả.</p><h3 id="anh-xa-cname" tabindex="-1">Ánh xạ CNAME <a class="header-anchor" href="#anh-xa-cname" aria-label="Permalink to &quot;Ánh xạ CNAME&quot;">​</a></h3><p>Ánh xạ CNAME cho phép người thuê kết nối tên miền riêng của họ với tên miền phụ do SaaS tạo ra, giúp xây dựng thương hiệu chuyên nghiệp.</p><p>Khi người thuê đăng ký, một tên miền phụ mặc định như <strong>username.rootdomain.com</strong> sẽ được tạo. Với CNAME, tên miền thật của họ có thể trỏ về tên miền phụ này.</p><p>Điều này giúp khách hàng tìm thấy cửa hàng dễ hơn và giữ được hình ảnh trực tuyến nhất quán, đáng tin cậy.</p><p>Việc ánh xạ được thiết lập thông qua nhà cung cấp DNS của người thuê và SaaS dưới quyền quản trị viên cấp cao, không cần thêm plugin nào khác.</p>',18)),u(t,{src:"/images/multi-tenant-ecommerce/multi-tenant.webp",alt:"Super Admin Login"})])}const q=h(o,[["render",e]]);export{v as __pageData,q as default};
